#!/usr/bin/env python3
import subprocess
import sys
import os
import shutil
import json
from datetime import datetime, timedelta
import tempfile

def run_command(cmd, check=True):
    result = subprocess.run(cmd, shell=True, capture_output=True, text=True)
    if check and result.returncode != 0:
        print(f"Error: {result.stderr}")
        sys.exit(1)
    return result

def check_outdated_dependencies():
    print("Checking for outdated dependencies...")
    result = run_command("pip list --outdated --format=json", check=False)
    if result.returncode == 0 and result.stdout.strip():
        outdated = json.loads(result.stdout)
        if outdated:
            print("\nWARNING: Outdated dependencies found:")
            for pkg in outdated:
                print(f"  {pkg['name']}: {pkg['version']} -> {pkg['latest_version']}")
            
            critical_packages = ['django', 'flask', 'requests', 'urllib3', 'cryptography', 'pyyaml']
            critical_outdated = [p for p in outdated if p['name'].lower() in critical_packages]
            
            if critical_outdated:
                print("\nERROR: Critical security packages are outdated!")
                for pkg in critical_outdated:
                    print(f"  {pkg['name']}: {pkg['version']} -> {pkg['latest_version']}")
                sys.exit(1)
            
            print("\nContinuing with deployment (no critical packages outdated)...")
    else:
        print("All dependencies are up to date.")

def install_dependencies():
    print("Installing dependencies from requirements.txt...")
    if not os.path.exists('requirements.txt'):
        print("Error: requirements.txt not found")
        sys.exit(1)
    
    run_command(f"{sys.executable} -m pip install --upgrade pip")
    run_command(f"{sys.executable} -m pip install -r requirements.txt")
    print("Dependencies installed successfully.")

def run_tests():
    print("\nRunning tests...")
    
    if os.path.exists('pytest.ini') or os.path.exists('tests'):
        run_command(f"{sys.executable} -m pytest -v --tb=short")
    elif os.path.exists('manage.py'):
        run_command(f"{sys.executable} manage.py test")
    elif os.path.exists('test.py'):
        run_command(f"{sys.executable} test.py")
    else:
        result = run_command(f"{sys.executable} -m unittest discover -s . -p 'test*.py'", check=False)
        if result.returncode != 0:
            print("Warning: No tests found or tests failed")
            response = input("Continue without tests? (y/n): ")
            if response.lower() != 'y':
                sys.exit(1)
    
    print("Tests passed successfully.")

def package_deployment():
    print("\nPackaging for deployment...")
    
    dist_dir = 'dist'
    if os.path.exists(dist_dir):
        shutil.rmtree(dist_dir)
    os.makedirs(dist_dir)
    
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    package_name = f"deployment_{timestamp}"
    package_path = os.path.join(dist_dir, package_name)
    
    os.makedirs(package_path)
    
    exclude_dirs = {'.git', '__pycache__', '.pytest_cache', 'venv', 'env', 
                    '.venv', 'node_modules', dist_dir, '.tox', 'htmlcov', '.coverage'}
    exclude_files = {'.pyc', '.pyo', '.pyd', '.so', '.dll', '.dylib', '.DS_Store'}
    
    for root, dirs, files in os.walk('.'):
        dirs[:] = [d for d in dirs if d not in exclude_dirs and not d.startswith('.')]
        
        rel_root = os.path.relpath(root, '.')
        if rel_root == '.':
            dest_root = package_path
        else:
            dest_root = os.path.join(package_path, rel_root)
            os.makedirs(dest_root, exist_ok=True)
        
        for file in files:
            if not any(file.endswith(ext) for ext in exclude_files):
                src = os.path.join(root, file)
                dst = os.path.join(dest_root, file)
                shutil.copy2(src, dst)
    
    archive_path = shutil.make_archive(package_path, 'zip', dist_dir, package_name)
    shutil.rmtree(package_path)
    
    print(f"Deployment package created: {archive_path}")
    
    with open(os.path.join(dist_dir, 'deployment_info.txt'), 'w') as f:
        f.write(f"Deployment Package Information\n")
        f.write(f"==============================\n")
        f.write(f"Timestamp: {datetime.now().isoformat()}\n")
        f.write(f"Package: {os.path.basename(archive_path)}\n")
        f.write(f"Size: {os.path.getsize(archive_path)} bytes\n")
    
    return archive_path

def main():
    print("=" * 60)
    print("Deployment Automation Script")
    print("=" * 60)
    
    start_time = datetime.now()
    
    try:
        install_dependencies()
        check_outdated_dependencies()
        run_tests()
        package_path = package_deployment()
        
        end_time = datetime.now()
        duration = (end_time - start_time).total_seconds()
        
        print("\n" + "=" * 60)
        print("Deployment preparation completed successfully!")
        print(f"Total time: {duration:.2f} seconds")
        print(f"Package ready: {package_path}")
        print("=" * 60)
        
    except KeyboardInterrupt:
        print("\n\nDeployment cancelled by user.")
        sys.exit(1)
    except Exception as e:
        print(f"\n\nDeployment failed: {str(e)}")
        sys.exit(1)

if __name__ == "__main__":
    main()